// @ts-nocheck
import { useState } from 'react';
import { useQuery, useQueryClient } from '@tanstack/react-query';
import { api } from '../../lib/api';
import { useWorkspaceStore, openQueryStoreTab } from '../../store/workspace';
import { useQueryStoreNavStore } from '../../store/query-store-nav';

function fmtDbTime(sec: number) {
  if (sec >= 3600) return `${(sec / 3600).toFixed(1)}h`;
  if (sec >= 60) return `${(sec / 60).toFixed(1)}m`;
  if (sec >= 1) return `${sec.toFixed(2)}s`;
  return `${(sec * 1000).toFixed(0)}ms`;
}

function fmtNum(n: number) { return n >= 1e6 ? `${(n/1e6).toFixed(1)}M` : n >= 1e3 ? `${(n/1e3).toFixed(1)}K` : String(n); }

const WAIT_HEX: Record<string, string> = {
  CPU: '#ef4444', Lock: '#f97316', LWLock: '#eab308', IO: '#3b82f6',
  BufferPin: '#a855f7', Client: '#9ca3af', IPC: '#06b6d4', Other: '#0ea5e9',
};
const PALETTE = ['#0ea5e9','#8b5cf6','#14b8a6','#f59e0b','#ec4899','#10b981','#6366f1','#f43f5e'];

function waitHex(name: string) { return WAIT_HEX[name] ?? '#0ea5e9'; }

const WINDOWS = ['15m', '30m', '1h', '6h', '24h', '7d', '30d'] as const;
type W = typeof WINDOWS[number];

function Loading() { return <div className="text-2xs text-nv-textMuted py-6 text-center animate-pulse">Loading…</div>; }
function Empty({ msg }: { msg: string }) { return <div className="text-2xs text-nv-textSubtle py-4 text-center">{msg}</div>; }

function MiniWaitChart({ waits }: { waits: any[] }) {
  if (!waits.length) return <Empty msg="No wait data for this query in the selected window." />;
  const total = waits.reduce((s, w) => s + Number(w.samples ?? 0), 0) || 1;
  return (
    <div className="flex items-end gap-1 h-10">
      {waits.slice(0, 8).map((w, i) => {
        const pct = Number(w.samples ?? 0) / total;
        const color = waitHex(w.waitClass);
        return (
          <div key={i} className="flex flex-col items-center gap-0.5 flex-1">
            <div title={`${w.waitClass}: ${w.waitType} (${(pct * 100).toFixed(0)}%)`}
              className="w-full rounded-t" style={{ height: `${Math.max(4, pct * 36)}px`, background: color }} />
            <span className="text-[9px] text-nv-textSubtle truncate w-full text-center">{w.waitClass}</span>
          </div>
        );
      })}
    </div>
  );
}

function StatsChart({ history }: { history: any[] }) {
  if (!history.length) return <Empty msg="No stats history in this window." />;
  const maxDb = Math.max(...history.map((r) => Number(r.dbTime ?? 0)), 1);
  return (
    <div className="flex items-end gap-0.5 h-12 mt-1">
      {history.map((r, i) => {
        const h = (Number(r.dbTime ?? 0) / maxDb) * 44;
        const ts = r.ts ? new Date(r.ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) : '';
        return (
          <div key={i} className="flex flex-col items-center flex-1 min-w-0" title={`DB Time: ${fmtDbTime(Number(r.dbTime ?? 0))} @ ${ts}`}>
            <div className="w-full rounded-t bg-sky-600/80" style={{ height: `${Math.max(2, h)}px` }} />
          </div>
        );
      })}
    </div>
  );
}

function AttributionSection({ attribution }: { attribution: any[] }) {
  const byDim: Record<string, any[]> = {};
  for (const r of attribution) {
    const d = r.dimension ?? 'unknown';
    if (!byDim[d]) byDim[d] = [];
    byDim[d].push(r);
  }
  const dimLabels: Record<string, string> = { application: 'Programs', user: 'Users', host: 'Machines' };
  if (!attribution.length) return <Empty msg="No attribution data. Attribution syncs from Query Sources on each DPA collector tick." />;
  return (
    <div className="space-y-3">
      {Object.entries(byDim).map(([dim, rows]) => {
        const total = rows.reduce((s, r) => s + Number(r.dbTime ?? r.totalDbTime ?? 0), 0) || 1;
        return (
          <div key={dim}>
            <p className="text-2xs font-medium text-nv-textMuted mb-1">{dimLabels[dim] ?? dim}</p>
            {rows.slice(0, 6).map((r, i) => {
              const val = Number(r.dbTime ?? r.totalDbTime ?? 0);
              const pct = (val / total) * 100;
              return (
                <div key={i} className="mb-1">
                  <div className="flex justify-between text-2xs">
                    <span className="text-nv-text truncate max-w-[60%]">{r.value ?? r.application ?? '—'}</span>
                    <span className="text-nv-textSubtle font-mono">{fmtDbTime(val)} ({pct.toFixed(0)}%)</span>
                  </div>
                  <div className="h-1.5 bg-nv-border/40 rounded-sm mt-0.5">
                    <div className="h-full rounded-sm bg-sky-600/70" style={{ width: `${pct}%` }} />
                  </div>
                </div>
              );
            })}
          </div>
        );
      })}
    </div>
  );
}

function PlansSection({ plans }: { plans: any[] }) {
  const [selected, setSelected] = useState(0);
  if (!plans.length) return <Empty msg="No execution plans captured. Enable Query Store plan capture." />;
  const plan = plans[selected];
  return (
    <div className="space-y-2">
      <div className="flex gap-1 flex-wrap">
        {plans.map((p, i) => (
          <button key={i} type="button" onClick={() => setSelected(i)}
            className={`nv-btn !py-0.5 !text-2xs ${selected === i ? 'bg-sky-900/40 text-sky-300' : ''} ${p.regression ? 'border-orange-700/60' : ''}`}>
            Plan {String(p.hash ?? '').slice(0, 8)}
            {p.regression && <span className="ml-1 text-orange-400">⚠ regression</span>}
          </button>
        ))}
      </div>
      {plan.ts && <p className="text-2xs text-nv-textSubtle">Captured: {new Date(plan.ts).toLocaleString()}</p>}
      {plan.sampleSql && (
        <pre className="text-2xs font-mono text-nv-text bg-nv-surface border border-nv-border rounded p-2 overflow-x-auto whitespace-pre-wrap max-h-24">
          {String(plan.sampleSql).slice(0, 500)}
        </pre>
      )}
      <pre className="text-2xs font-mono text-nv-textMuted bg-nv-surface border border-nv-border rounded p-2 overflow-auto max-h-48 whitespace-pre-wrap">
        {plan.plan ? (typeof plan.plan === 'string' ? plan.plan : JSON.stringify(plan.plan, null, 2)).slice(0, 3000) : '(no plan text)'}
      </pre>
    </div>
  );
}

/** Per-query wait trend: colored stacked area by wait class */
function PerQueryWaitTrend({ rows }: { rows: { bucket: string; wait_class: string; samples: number }[] }) {
  if (!rows.length) return <Empty msg="No per-query wait samples yet. Ensure DPA collector is running and Query Store captured this query." />;

  const COLORS: Record<string, string> = {
    CPU: '#f97316', Lock: '#ef4444', IO: '#3b82f6', LWLock: '#eab308',
    Network: '#8b5cf6', IPC: '#06b6d4', Buffer: '#14b8a6', Other: '#6b7280',
    BufferPin: '#a855f7', Client: '#94a3b8',
  };

  // Group by bucket
  const bucketMap = new Map<string, Record<string, number>>();
  const allClasses = new Set<string>();
  for (const r of rows) {
    const key = r.bucket;
    if (!bucketMap.has(key)) bucketMap.set(key, {});
    bucketMap.get(key)![r.wait_class] = (bucketMap.get(key)![r.wait_class] ?? 0) + Number(r.samples);
    allClasses.add(r.wait_class);
  }
  const buckets = [...bucketMap.entries()].sort((a, b) => a[0].localeCompare(b[0]));
  const classes = [...allClasses];
  const maxTotal = Math.max(...buckets.map(([, m]) => Object.values(m).reduce((s, v) => s + v, 0)), 0.1);

  const W = 600, H = 60, padL = 0, padR = 0, padT = 2, padB = 14;
  const cw = W - padL - padR;
  const ch = H - padT - padB;
  const slot = cw / buckets.length;
  const barW = Math.min(slot * 0.8, 20);

  return (
    <div>
      <svg viewBox={`0 0 ${W} ${H}`} width="100%" height={H} preserveAspectRatio="none" className="block">
        {buckets.map(([ts, classMap], i) => {
          const x = padL + slot * i + (slot - barW) / 2;
          let yCursor = padT + ch;
          return (
            <g key={ts}>
              {classes.map((cls) => {
                const v = classMap[cls] ?? 0;
                if (v <= 0) return null;
                const h = (v / maxTotal) * ch;
                yCursor -= h;
                return <rect key={cls} x={x} y={yCursor} width={barW} height={h}
                  fill={COLORS[cls] ?? '#6b7280'} opacity={0.85} />;
              })}
            </g>
          );
        })}
        {/* time labels: first and last */}
        {buckets.length > 0 && [0, buckets.length - 1].map((i) => {
          const x = padL + slot * i + slot / 2;
          const label = new Date(buckets[i][0]).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
          return <text key={i} x={x} y={H - 1} textAnchor="middle" fontSize={8} fill="#64748b">{label}</text>;
        })}
      </svg>
      <div className="flex flex-wrap gap-x-3 gap-y-0.5 mt-1">
        {classes.map((cls) => (
          <span key={cls} className="flex items-center gap-1 text-[9px] text-nv-textSubtle">
            <span className="inline-block w-2 h-2 rounded-sm" style={{ background: COLORS[cls] ?? '#6b7280' }} />
            {cls}
          </span>
        ))}
      </div>
    </div>
  );
}

export function QueryDetailPanel({ connectionId, connectionName, queryId }: { connectionId: string; connectionName?: string; queryId: string }) {
  const [window, setWindow] = useState<W>('24h');
  const qc = useQueryClient();

  const detail = useQuery({
    queryKey: ['query-detail', connectionId, queryId, window],
    queryFn: () => api.dpaQueryDetail(connectionId, queryId, window),
    enabled: !!queryId,
    staleTime: 30000,
  });

  // Per-query wait trend from qs_waits_snapshot (the DPA per-query samples)
  const perQueryWaits = useQuery({
    queryKey: ['query-per-waits', connectionId, queryId, window],
    queryFn: () => api.dpaQueryWaits(connectionId, queryId, window),
    enabled: !!queryId,
    staleTime: 30000,
  });

  const qsQuery = useQuery({
    queryKey: ['qs-query', connectionId, queryId],
    queryFn: () => api.queryStoreGetQuery(connectionId, queryId),
    enabled: !!queryId,
    staleTime: 60000,
  });

  const qsHistory = useQuery({
    queryKey: ['qs-history', connectionId, queryId],
    queryFn: () => api.queryStoreQueryHistory(connectionId, queryId, 40),
    enabled: !!queryId,
    staleTime: 60000,
  });

  const qsPlans = useQuery({
    queryKey: ['qs-plans-detail', connectionId, queryId],
    queryFn: () => api.queryStoreQueryPlans(connectionId, queryId, 20),
    enabled: !!queryId,
    staleTime: 60000,
  });

  const d = detail.data;
  const queryText = String(d?.query?.text ?? qsQuery.data?.query?.normalizedText ?? qsQuery.data?.query?.normalized_text ?? '');
  const mergedPlans = (d?.plans?.length ? d.plans : qsPlans.data?.plans ?? []) as any[];

  function openQueryStore() {
    useQueryStoreNavStore.getState().openQuery({ connectionId, queryId, sqlText: queryText });
    openQueryStoreTab({ connectionId, connectionName });
  }

  function openWaitDetail(waitClass: string) {
    useWorkspaceStore.getState().openTab({
      type: 'waitDetail',
      title: `Wait · ${waitClass}`,
      connectionId,
      connectionName,
      waitClass,
    });
  }

  function refresh() {
    qc.invalidateQueries({ queryKey: ['query-detail', connectionId, queryId] });
    qc.invalidateQueries({ queryKey: ['qs-query', connectionId, queryId] });
  }

  return (
    <div className="h-full flex flex-col text-xs">
      {/* header */}
      <div className="px-3 py-2 border-b border-nv-border flex items-center gap-2 flex-wrap shrink-0 bg-gradient-to-r from-slate-950 to-indigo-950/30">
        <span className="font-semibold text-nv-text">Query Detail</span>
        {connectionName && <span className="text-nv-textMuted">· {connectionName}</span>}
        <div className="ml-auto flex items-center gap-1">
          <button type="button" className="nv-btn !py-0.5 !text-2xs text-sky-400 border-sky-800/60" onClick={openQueryStore}>
            Query Store ↗
          </button>
          {WINDOWS.map((wk) => (
            <button key={wk} type="button" onClick={() => setWindow(wk)}
              className={`nv-btn !py-0.5 !text-2xs ${window === wk ? 'bg-sky-900/40 text-sky-300' : ''}`}>{wk}</button>
          ))}
          <button type="button" className="nv-btn !py-0.5 !text-2xs" onClick={refresh}>↻ Refresh</button>
        </div>
      </div>

      {detail.isLoading && <Loading />}
      {!detail.isLoading && d?.error && <Empty msg={d.error} />}
      {!detail.isLoading && d && !d.error && (
        <div className="flex-1 overflow-auto p-3 space-y-4">
          {/* query text */}
          <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
            <div className="flex items-center gap-2 mb-2">
              <span className="font-medium text-nv-text">SQL</span>
              {d.query?.schema && <span className="text-2xs text-nv-textSubtle bg-indigo-900/40 px-1.5 py-0.5 rounded">{d.query.schema}</span>}
              <span className="text-2xs text-nv-textSubtle ml-auto font-mono">{String(d.query?.id ?? '').slice(0, 12)}</span>
            </div>
            <pre className="text-2xs font-mono text-nv-text bg-nv-panel border border-nv-border/40 rounded p-2 overflow-x-auto whitespace-pre-wrap max-h-36">
              {queryText.slice(0, 2000)}
            </pre>
          </div>

          {/* Query Store metadata */}
          {qsQuery.data?.query && (
            <div className="border border-indigo-800/40 rounded-lg p-3 bg-indigo-950/10">
              <div className="flex items-center gap-2 mb-2">
                <span className="font-medium text-indigo-200">Query Store</span>
                <button type="button" className="nv-btn !py-0.5 !text-2xs ml-auto" onClick={openQueryStore}>Full analysis ↗</button>
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-2 text-2xs">
                <div><span className="text-nv-textSubtle">Plans</span><div className="font-mono text-nv-text">{qsQuery.data.query.planCount ?? qsPlans.data?.plans?.length ?? '—'}</div></div>
                <div><span className="text-nv-textSubtle">Executions</span><div className="font-mono text-nv-text">{fmtNum(Number(qsQuery.data.query.totalCalls ?? qsQuery.data.query.total_calls ?? 0))}</div></div>
                <div><span className="text-nv-textSubtle">Avg time</span><div className="font-mono text-nv-text">{qsQuery.data.query.avgSec != null ? `${Number(qsQuery.data.query.avgSec).toFixed(3)}s` : '—'}</div></div>
                <div><span className="text-nv-textSubtle">History points</span><div className="font-mono text-nv-text">{qsHistory.data?.history?.length ?? qsHistory.data?.points?.length ?? 0}</div></div>
              </div>
            </div>
          )}

          {/* KPIs + waits + advisors row */}
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <p className="font-medium text-nv-text mb-2">Summary ({window})</p>
              <div className="space-y-1">
                <div className="flex justify-between text-2xs">
                  <span className="text-nv-textSubtle">Total DB Time</span>
                  <span className="text-sky-300 font-mono">{fmtDbTime(Number(d.totals?.dbTime ?? 0))}</span>
                </div>
                <div className="flex justify-between text-2xs">
                  <span className="text-nv-textSubtle">Total Executions</span>
                  <span className="font-mono text-nv-text">{fmtNum(Number(d.totals?.calls ?? 0))}</span>
                </div>
                <div className="flex justify-between text-2xs">
                  <span className="text-nv-textSubtle">Avg per exec</span>
                  <span className="font-mono text-nv-text">{d.totals?.calls ? fmtDbTime(Number(d.totals.dbTime) / Number(d.totals.calls)) : '—'}</span>
                </div>
              </div>
              <p className="text-2xs font-medium text-nv-textMuted mt-3 mb-1">DB Time Trend</p>
              <StatsChart history={d.statsHistory ?? []} />
            </div>

            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              {perQueryWaits.data?.rows?.length > 0 ? (
                <>
                  <div className="flex items-center gap-2 mb-2">
                    <p className="font-medium text-nv-text">Avg Active Sessions (per-query)</p>
                    <span className="text-[9px] bg-sky-900/30 text-sky-400 px-1.5 py-0.5 rounded">DPA mode</span>
                  </div>
                  <PerQueryWaitTrend rows={perQueryWaits.data.rows} />
                </>
              ) : (
                <>
                  <p className="font-medium text-nv-text mb-2">Top Waits (connection level)</p>
                  <MiniWaitChart waits={d.waitBreakdown ?? []} />
                  <div className="mt-2 space-y-0.5">
                    {(d.waitBreakdown ?? []).slice(0, 5).map((w: any, i: number) => (
                      <button key={i} type="button"
                        className="flex items-center justify-between gap-2 text-2xs w-full hover:bg-orange-950/20 rounded px-1 py-0.5"
                        onClick={() => openWaitDetail(w.waitClass)}>
                        <span className="flex items-center gap-1">
                          <span className="w-2 h-2 rounded-sm inline-block" style={{ background: waitHex(w.waitClass) }} />
                          <span className="text-nv-text">{w.waitClass}</span>
                        </span>
                        <span className="text-nv-textSubtle font-mono truncate max-w-[120px]">{w.waitType}</span>
                        <span className="text-nv-textSubtle font-mono">{Number(w.samples).toFixed(0)}</span>
                      </button>
                    ))}
                  </div>
                </>
              )}
            </div>

            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <p className="font-medium text-nv-text mb-2">Advisors</p>
              {!(d.advisors?.length) && <Empty msg="No issues detected." />}
              {(d.advisors ?? []).map((a: any, i: number) => (
                <div key={i} className={`mb-2 p-2 rounded border text-2xs ${a.severity === 'warning' ? 'border-orange-700/50 bg-orange-950/10' : 'border-nv-border bg-nv-surface/30'}`}>
                  <span className={`font-medium ${a.severity === 'warning' ? 'text-orange-300' : 'text-nv-text'}`}>{a.type.replace(/_/g, ' ')}</span>
                  <p className="text-nv-textMuted mt-0.5">{a.message}</p>
                </div>
              ))}
            </div>
          </div>

          {/* Attribution */}
          <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
            <p className="font-medium text-nv-text mb-2">Programs / Machines / Users</p>
            <AttributionSection attribution={[...(d.attribution ?? [])]} />
          </div>

          {/* Plans */}
          <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
            <p className="font-medium text-nv-text mb-2">Execution Plan History</p>
            <PlansSection plans={mergedPlans} />
          </div>

          {/* Blocking events */}
          {(d.blockingEvents?.length > 0) && (
            <div className="border border-nv-border rounded-lg p-3 bg-nv-surface/40">
              <p className="font-medium text-nv-text mb-2">Blocking Events ({window})</p>
              <div className="space-y-1 max-h-48 overflow-auto">
                {d.blockingEvents.map((e: any) => (
                  <div key={e.id} className="px-2 py-1 rounded border border-nv-border/40 bg-nv-surface/30">
                    <div className="flex items-center gap-2">
                      <span className={`text-2xs font-medium ${e.severity === 'critical' ? 'text-red-400' : 'text-orange-400'}`}>{e.eventType}</span>
                      <span className="text-2xs text-nv-textSubtle ml-auto">{e.timestamp ? new Date(e.timestamp).toLocaleString() : ''}</span>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}
